const body = $json.body ?? $json;
const jobDescription = (body.job_description || '').toString().trim();
const profile = (body.profile || 'devops').toString().trim().toLowerCase();
const customPrompt = (body.custom_prompt || '').toString().trim();

if (!jobDescription) {
  throw new Error('job_description is required in the request body');
}
if (!['devops', 'backend'].includes(profile)) {
  throw new Error("profile must be either 'devops' or 'backend'");
}

const cvPathMap = {
  devops: '/home/node/.n8n-files/cv_devops_v2.html',
  backend: '/home/node/.n8n-files/cv_backend_v2.html'
};

const formatPart = (n) => String(n).padStart(2, '0');
const now = new Date();
const timestamp = `${now.getFullYear()}-${formatPart(now.getMonth()+1)}-${formatPart(now.getDate())}_${formatPart(now.getHours())}-${formatPart(now.getMinutes())}-${formatPart(now.getSeconds())}`;

const outputFileName = `cv-${profile}-${timestamp}.html`;
const outputFilePath = `/home/node/.n8n-files/generated/${outputFileName}`;

return [{
  json: {
    profile,
    job_description: jobDescription,
    custom_prompt: customPrompt,
    source_cv_path: cvPathMap[profile],
    output_file_name: outputFileName,
    output_file_path: outputFilePath,
    requested_at: now.toISOString()
  }
}];

const fs = require('fs');
const cvPath = $json.source_cv_path;

if (!fs.existsSync(cvPath)) {
  throw new Error(`CV file not found at path: ${cvPath}`);
}

const html = fs.readFileSync(cvPath, 'utf8');

if (!html || !html.trim()) {
  throw new Error('CV file is empty');
}

return [{
  json: {
    ...$json,
    base_cv_html: html
  }
}];

const profile = $json.profile;
const jobDescription = $json.job_description;
const baseCvHtml = $json.base_cv_html;
const customPrompt = $json.custom_prompt || '';

let prompt;
if (customPrompt) {
  // Use the user's custom prompt — append job description and base CV automatically
  prompt = `${customPrompt}

Selected profile: ${profile}

Job Description:
${jobDescription}

Original CV HTML:
${baseCvHtml}`;
} else {
  // Default ATS-optimisation prompt
  prompt = `You are an expert CV writer and ATS optimization specialist.

You will be given a candidate's existing CV in HTML format and a job description. Your task is to produce a tailored version of the CV that achieves 90%+ ATS compatibility score for the given job description.

STRICT RULES:
- Output ONLY the complete, valid HTML document. No explanations, no markdown fences, no commentary.
- Preserve the EXACT same HTML structure, CSS styles, class names, and visual layout as the original CV.
- Do NOT add or remove any HTML sections, CSS rules, or structural elements.
- Only modify text content (job titles, summaries, skill lists, bullet points, descriptions) to better match the job description.
- Do NOT invent experience, certifications, education, companies, dates, or projects that are not in the original CV.
- Rephrase and reorder existing content to highlight relevance to the job description.
- Integrate ATS-critical keywords from the job description ONLY where they genuinely match existing experience.
- Place the most relevant experience and skills first.
- Keep all contact details, name, and dates exactly as in the original.
- The output must be a single complete HTML file that renders identically in structure to the original.

Selected profile: ${profile}

Job Description:
${jobDescription}

Original CV HTML:
${baseCvHtml}`;
}

return [{
  json: {
    ...$json,
    anthropic_model: 'claude-sonnet-4-6',
    anthropic_prompt: prompt
  }
}];

const meta = $('Validate + Select CV').item.json;
const content = $json.content || [];
const generatedCv = content
  .filter(part => part.type === 'text')
  .map(part => part.text)
  .join('\n')
  .trim();

if (!generatedCv) {
  throw new Error('Claude returned an empty CV');
}

const cleanedCv = generatedCv
  .replace(/^```html\s*/i, '')
  .replace(/^```\s*/i, '')
  .replace(/\s*```$/i, '')
  .trim();

return [{
  json: {
    profile: meta.profile,
    requested_at: meta.requested_at,
    job_description: meta.job_description,
    source_cv_path: meta.source_cv_path,
    output_file_name: meta.output_file_name,
    output_file_path: meta.output_file_path,
    generated_cv_html: cleanedCv
  }
}];

const fs = require('fs');
const path = require('path');

const html = $json.generated_cv_html;
const filePath = $json.output_file_path;

if (!html) throw new Error('generated_cv_html is empty');
if (!filePath) throw new Error('output_file_path is missing');

const dir = path.dirname(filePath);
if (!fs.existsSync(dir)) {
  fs.mkdirSync(dir, { recursive: true });
}

fs.writeFileSync(filePath, html, 'utf8');

return [{ json: { ...$json } }];
